            response.sendError(HttpServletResponse.SC_FORBIDDEN, "Invalid CSRF token");
            return;
        }

        String op = request.getParameter("op");
        if (op == null) {
            response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Missing operation parameter");
            return;
