                    response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Invalid input parameters");
                    return;
                }

                // Additional input sanitization (e.g., whitelist patterns)
                if (!banji_name.matches("[a-zA-Z0-9_\\u4e00-\\u9fa5]{1,50}") ||
                    !zhuanye.matches("[a-zA-Z0-9_\\u4e00-\\u9fa5]{1,50}") ||
