                    response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Invalid characters in input");
                    return;
                }

                BanjiBean bean = new BanjiBean();
                bean.setBanji_name(banji_name.trim());
                bean.setZhuanye(zhuanye.trim());
                bean.setFudaoyuan(fudaoyuan.trim());
                bean.setRenshu(Integer.parseInt(renshuStr));

                banjiDao.save(bean);
